```class Solution {
public:
    int maxConsecutiveAnswers(string answerKey, int k) {
        int n = answerKey.size();
        int res = 0, cntT = 0, cntF = 0;
        int l = 0;
        for (int r = 0; r < n; r++) {
            if (answerKey[r] == 'T') cntT++;
            else cntF++;
            while (cntT > k && cntF > k) {
                if (answerKey[l] == 'T') cntT--;
                else cntF--;
                l++;
            }
            res = max(res, r - l + 1);
        }
        return res;
    }
};
